def trimmed_mean(nums):
    if not nums:
        return None

    nums.sort()
    n = len(nums)
    if n <= 1:
        return sum(nums[1:-1]) / (n - 2) if n > 1 else None

    min_index, max_index = 0, n - 1
    while nums[min_index] == nums[min_index + 1]:
        min_index += 1
    while nums[max_index] == nums[max_index - 1]:
        max_index -= 1

    return sum(nums[min_index + 1:max_index - 1]) / (n - 4)
